# module: kms_key

variable "alias" { type = string  # KMS alias }
variable "enable_rotation" { type = bool  # Rotate annually }

output "key_arn" { value = aws_kms_key.this.arn  # Key ARN }
output "key_id" { value = aws_kms_key.this.key_id  # Key ID }

# module: s3_secure_bucket

variable "name" { type = string  # Bucket name }
variable "kms_key_arn" { type = string  # SSE-KMS key }
variable "lifecycle_days" { type = number  # Expire after days }

output "bucket_id" { value = aws_s3_bucket.this.id  # ID }
output "bucket_arn" { value = aws_s3_bucket.this.arn  # ARN }

# module: iam_role_oidc

variable "role_name" { type = string  # Role name }
variable "oidc_provider_arn" { type = string  # OIDC provider }
variable "subject_claims" { type = list(string)  # Allowed sub }

output "role_arn" { value = aws_iam_role.this.arn  # Role ARN }
